export function getCuratedRun(id: string): CuratedRun | undefined {
  return CURATED_MANHATTAN_RUNS.find((r) => r.id === id);
}

export function curatedRunToGpx(run: CuratedRun): string {
  const pts = run.coords
    .map(([lat, lng]) => `    <trkpt lat="${lat.toFixed(6)}" lon="${lng.toFixed(6)}"></trkpt>`)
    .join("\n");
  return `<?xml version="1.0" encoding="UTF-8"?>
<gpx version="1.1" creator="PaceCasso" xmlns="http://www.topografix.com/GPX/1/1">
  <trk>
    <name>${run.title} — PaceCasso curated run</name>
    <desc>${run.area} · ${run.distanceKm} km · verified walkable</desc>
    <trkseg>
${pts}
    </trkseg>
  </trk>
</gpx>`;
}
